CREATE VIEW `dwd_read_admobrewardlog_view` (`dt` COMMENT "createtime 分区", `product_id` COMMENT "产品id", `id` COMMENT "自增id", `user_id` COMMENT "用户id", `admob_id` COMMENT "广告id", `award_type` COMMENT " '奖励类型 0：礼券 1：章节'", `award_num` COMMENT "奖励数量", `awardex_pire` COMMENT "奖励过期", `book_id` COMMENT "书籍id", `chapter_ids` COMMENT "章节id", `price` COMMENT "章节价格", `create_tm` COMMENT "创建时间", `app_id` COMMENT "应用程序id", `etl_tm` COMMENT "etl时间")
COMMENT "看广告获得奖励记录表" AS SELECT `ods_log`.`ods_tidb_readerlog_AdmobRewardLog`.`dt`, `ods_log`.`ods_tidb_readerlog_AdmobRewardLog`.`product_id`, `ods_log`.`ods_tidb_readerlog_AdmobRewardLog`.`Id`, `ods_log`.`ods_tidb_readerlog_AdmobRewardLog`.`UserId` AS `user_id`, `ods_log`.`ods_tidb_readerlog_AdmobRewardLog`.`AdMobId` AS `admob_id`, `ods_log`.`ods_tidb_readerlog_AdmobRewardLog`.`AwardType` AS `award_type`, `ods_log`.`ods_tidb_readerlog_AdmobRewardLog`.`AwardNum` AS `award_num`, `ods_log`.`ods_tidb_readerlog_AdmobRewardLog`.`AwardExpire` AS `awardex_pire`, `ods_log`.`ods_tidb_readerlog_AdmobRewardLog`.`BookId` AS `book_id`, `ods_log`.`ods_tidb_readerlog_AdmobRewardLog`.`ChapterIds` AS `chapter_ids`, `ods_log`.`ods_tidb_readerlog_AdmobRewardLog`.`Price`, `ods_log`.`ods_tidb_readerlog_AdmobRewardLog`.`CreateTime` AS `create_tm`, `ods_log`.`ods_tidb_readerlog_AdmobRewardLog`.`AppId` AS `app_id`, now() AS `etl_tm`
FROM `ods_log`.`ods_tidb_readerlog_AdmobRewardLog`;
